// Parse Ollama creator response
const rawResponse = $input.first().json;

let productPackage;
try {
  const content = rawResponse?.message?.content || rawResponse?.response || '';
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/) || 
                    content.match(/({[\s\S]*})/);
  const jsonStr = jsonMatch ? jsonMatch[1] || jsonMatch[0] : content;
  productPackage = JSON.parse(jsonStr.trim());
} catch(e) {
  productPackage = {
    error: true,
    error_message: e.message,
    raw_response: rawResponse?.message?.content?.substring(0, 500)
  };
}

// Add workflow metadata
productPackage.created_at = new Date().toISOString();
productPackage.publish_status = 'ready';
productPackage.publish_etsy = false;
productPackage.publish_gumroad = false;
productPackage.publish_payhip = false;

return [{ json: productPackage }];

// Generate phi3-optimized image generation prompts for the product
// phi3 is great for structured, precise prompt generation
const product = $input.first().json;

const imagePromptRequest = {
  product_id: product.product_id,
  product_title: product.listing?.title,
  category: product.category,
  prompts_needed: [
    'product_mockup',
    'listing_thumbnail',
    'social_preview'
  ]
};

return [{ json: imagePromptRequest }];

