// Merge product package with image prompts
const productPackage = $('⚙️ Parse Product Package').first().json;
const imagePromptsRaw = $input.first().json;

let imagePrompts;
try {
  const content = imagePromptsRaw?.message?.content || imagePromptsRaw?.response || '';
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/) || 
                    content.match(/({[\s\S]*})/);
  const jsonStr = jsonMatch ? jsonMatch[1] || jsonMatch[0] : content;
  imagePrompts = JSON.parse(jsonStr.trim());
} catch(e) {
  imagePrompts = { error: 'Could not parse image prompts' };
}

// Build the complete product record
const completeProduct = {
  ...productPackage,
  image_prompts: imagePrompts,

  // Ready for publishing
  ready_to_publish: true,
  publish_checklist: {
    create_product_files: false,
    upload_to_etsy: false,
    upload_to_gumroad: false,
    upload_to_payhip: false,
    post_instagram: false,
    post_facebook: false,
    post_tiktok: false,
    post_pinterest: false,
    post_youtube: false
  }
};

return [{ json: completeProduct }];
